import{_ as l,o as d,c as a,ae as r}from"./chunks/framework.DAK3ioSj.js";const b=JSON.parse('{"title":"Skill 召回技术","description":"","frontmatter":{},"headers":[],"relativePath":"radar/category-02-recall.md","filePath":"radar/category-02-recall.md"}'),e={name:"radar/category-02-recall.md"};function i(o,t,h,s,n,k){return d(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="skill-召回技术" tabindex="-1">Skill 召回技术 <a class="header-anchor" href="#skill-召回技术" aria-label="Permalink to &quot;Skill 召回技术&quot;">​</a></h1><blockquote><p><strong>版本</strong>: v1.0.0 <strong>创建日期</strong>: 2026-05-10 <strong>分类</strong>: Skill 生命周期 - 第二阶段 <strong>成熟度</strong>: 🟢 成熟期 | 综合评分: 0.66</p></blockquote><hr><h2 id="一、技术概述" tabindex="-1">一、技术概述 <a class="header-anchor" href="#一、技术概述" aria-label="Permalink to &quot;一、技术概述&quot;">​</a></h2><p><strong>Skill 召回</strong>（也称 Skill 路由/Skill 调度）是智能体基于用户意图、上下文与场景特征，从 Skill 库中精准匹配最优 Skill/Skill 组合，完成从意图到执行的精准映射。</p><p>核心目标：实现&quot;需求-场景-Skill&quot;最优匹配，避免错配、漏召、过召，保障执行准确率与体验。</p><hr><h2 id="二、核心技术领域" tabindex="-1">二、核心技术领域 <a class="header-anchor" href="#二、核心技术领域" aria-label="Permalink to &quot;二、核心技术领域&quot;">​</a></h2><h3 id="_2-1-意图识别" tabindex="-1">2.1 意图识别 <a class="header-anchor" href="#_2-1-意图识别" aria-label="Permalink to &quot;2.1 意图识别&quot;">​</a></h3><p>将用户自然语言映射为 Skill 需求，理解用户真正想要什么。</p><table tabindex="0"><thead><tr><th>技术</th><th>描述</th><th>成熟度</th></tr></thead><tbody><tr><td>文本分类</td><td>将用户输入分类到预定类别</td><td>🟢 成熟</td></tr><tr><td>语义匹配</td><td>基于 Embedding 的相似度计算</td><td>🟢 成熟</td></tr><tr><td>上下文理解</td><td>结合对话历史理解意图</td><td>🟡 成长期</td></tr></tbody></table><h3 id="_2-2-召回算法" tabindex="-1">2.2 召回算法 <a class="header-anchor" href="#_2-2-召回算法" aria-label="Permalink to &quot;2.2 召回算法&quot;">​</a></h3><p>从大规模 Skill 库中高效召回相关 Skill。</p><table tabindex="0"><thead><tr><th>技术</th><th>描述</th><th>成熟度</th></tr></thead><tbody><tr><td>向量检索</td><td>基于 Embedding 的最近邻检索</td><td>🟢 成熟</td></tr><tr><td>混合检索</td><td>关键词 + 向量混合检索</td><td>🟢 成熟</td></tr><tr><td>图检索</td><td>利用 Skill 元数据关系图检索</td><td>🟡 成长期</td></tr><tr><td>多路召回</td><td>多路召回结果融合</td><td>🟡 成长期</td></tr></tbody></table><h3 id="_2-3-路由策略" tabindex="-1">2.3 路由策略 <a class="header-anchor" href="#_2-3-路由策略" aria-label="Permalink to &quot;2.3 路由策略&quot;">​</a></h3><p>大规模 Skill 库下的选择策略，决定使用哪个 Skill。</p><table tabindex="0"><thead><tr><th>技术</th><th>描述</th><th>成熟度</th></tr></thead><tbody><tr><td>规则路由</td><td>基于规则的固定映射</td><td>🟢 成熟</td></tr><tr><td>学习路由</td><td>基于强化学习/深度学习的动态路由</td><td>🟡 成长期</td></tr><tr><td>技能感知路由</td><td>显式建模 Skill 能力进行路由</td><td>🟡 成长期</td></tr><tr><td>Pareto 优化</td><td>性能与成本间的原理性平衡</td><td>🟡 成长期</td></tr></tbody></table><h3 id="_2-4-结构感知检索" tabindex="-1">2.4 结构感知检索 <a class="header-anchor" href="#_2-4-结构感知检索" aria-label="Permalink to &quot;2.4 结构感知检索&quot;">​</a></h3><p>利用 Skill 元数据提升检索精度。</p><table tabindex="0"><thead><tr><th>技术</th><th>描述</th><th>成熟度</th></tr></thead><tbody><tr><td>能力树</td><td>层级化技能能力建模</td><td>🟡 成长期</td></tr><tr><td>DAG 编排</td><td>多 Skill 依赖关系编排</td><td>🟡 成长期</td></tr><tr><td>元数据增强</td><td>利用 Skill 描述、标签增强检索</td><td>🟢 成熟</td></tr></tbody></table><hr><h2 id="三、代表技术与项目" tabindex="-1">三、代表技术与项目 <a class="header-anchor" href="#三、代表技术与项目" aria-label="Permalink to &quot;三、代表技术与项目&quot;">​</a></h2><h3 id="_3-1-skillrouter" tabindex="-1">3.1 SkillRouter <a class="header-anchor" href="#_3-1-skillrouter" aria-label="Permalink to &quot;3.1 SkillRouter&quot;">​</a></h3><p>破解大规模 Skills 选择难题的新范式。</p><p><strong>核心能力</strong>：</p><ul><li>多路召回 + 结果融合</li><li>基于强化学习的动态路由</li><li>支持千级规模 Skill 库</li></ul><p><strong>技术亮点</strong>：22.5% 性能提升，700 倍学习成本降低</p><h3 id="_3-2-skillorchestra" tabindex="-1">3.2 SkillOrchestra <a class="header-anchor" href="#_3-2-skillorchestra" aria-label="Permalink to &quot;3.2 SkillOrchestra&quot;">​</a></h3><p>基于技能的 Agent 路由策略。</p><p><strong>核心能力</strong>：</p><ul><li>技能手册学习</li><li>Pareto 验证筛选</li><li>模式感知 + 技能驱动的智能体选择</li></ul><p><strong>技术亮点</strong>：比 Router-R1 学习成本降低 700 倍，比 ToolOrchestra 降低 300 倍</p><h3 id="_3-3-graph-of-skills" tabindex="-1">3.3 Graph of Skills <a class="header-anchor" href="#_3-3-graph-of-skills" aria-label="Permalink to &quot;3.3 Graph of Skills&quot;">​</a></h3><p>千级规模 Skill 库的结构感知检索方案。</p><p><strong>核心能力</strong>：</p><ul><li>结构感知检索</li><li>43.6% 成功率提升</li><li>支持大规模 Skill 库</li></ul><h3 id="_3-4-agentskillos" tabindex="-1">3.4 AgentSkillOS <a class="header-anchor" href="#_3-4-agentskillos" aria-label="Permalink to &quot;3.4 AgentSkillOS&quot;">​</a></h3><p>生态级规模下技能的组织、编排与基准测试。</p><p><strong>核心能力</strong>：</p><ul><li>能力树构建</li><li>DAG 执行计划编排</li><li>层级化检索</li></ul><hr><h2 id="四、技术成熟度分析" tabindex="-1">四、技术成熟度分析 <a class="header-anchor" href="#四、技术成熟度分析" aria-label="Permalink to &quot;四、技术成熟度分析&quot;">​</a></h2><table tabindex="0"><thead><tr><th>技术</th><th>技术成熟度</th><th>创新性</th><th>落地程度</th><th>生态活跃度</th><th>综合</th></tr></thead><tbody><tr><td>意图识别</td><td>0.75</td><td>0.55</td><td>0.75</td><td>0.65</td><td>0.68</td></tr><tr><td>召回算法</td><td>0.75</td><td>0.55</td><td>0.70</td><td>0.60</td><td>0.66</td></tr><tr><td>路由策略</td><td>0.70</td><td>0.65</td><td>0.65</td><td>0.55</td><td>0.64</td></tr><tr><td>结构感知检索</td><td>0.65</td><td>0.60</td><td>0.55</td><td>0.50</td><td>0.58</td></tr><tr><td><strong>阶段综合</strong></td><td><strong>0.75</strong></td><td><strong>0.55</strong></td><td><strong>0.70</strong></td><td><strong>0.60</strong></td><td><strong>0.66</strong></td></tr></tbody></table><hr><h2 id="五、学习资源" tabindex="-1">五、学习资源 <a class="header-anchor" href="#五、学习资源" aria-label="Permalink to &quot;五、学习资源&quot;">​</a></h2><ul><li><a href="./../tech-blog/Agent Skills洞察与实践/【Agent Skills洞察与实践】12-SkillRouter：破解大规模Skills选择难题的新范式.html">SkillRouter：破解大规模Skills选择难题</a></li><li><a href="./../tech-blog/Agent Skills洞察与实践/【Agent Skills洞察与实践】21-Graph of Skills：千级规模Skill库的结构感知检索方案，成功率提升43.6%.html">Graph of Skills：千级规模Skill库的结构感知检索</a></li><li><a href="./../tech-blog/Agent Skills洞察与实践/【Agent Skills洞察与实践】05-集成Skills的单智能体，能否终结多智能体？.html">AgentSkillOS：生态级规模下智能体技能的组织</a></li><li><a href="https://atomgit.com/openeuler/witty-skill-insight" target="_blank" rel="noreferrer">witty-skill-insight 项目</a></li></ul>',46)])])}const c=l(e,[["render",i]]);export{b as __pageData,c as default};
